DECLARE sheet VARCHAR;
DECLARE xml_entity XML;
DECLARE myparams ANY;
sheet := 'virt://WS.WS.SYS_DAV_RES.RES_FULL_PATH.RES_CONTENT:/DAV/stylesheets/mysheet.xsl';
xml_entity := (SELECT content FROM xml_data WHERE id BETWEEN 1 AND 2);
myparams := vector((SELECT param_name FROM xml_data WHERE param_value IS NOT NULL AND param_name NOT IN ('chapter'))); 
SELECT http_value(xslt(sheet, xml_entity, myparams));

DECLARE xml_result XML;
xml_result := xslt('virt://WS.WS.SYS_DAV_RES.RES_FULL_PATH.RES_CONTENT:/DAV/stylesheets/mysheet.xsl', xtree_doc((SELECT content FROM xml_data WHERE id = 1)), vector());
SELECT CASE WHEN xml_result IS NULL THEN 'Transformation Failed' ELSE 'Transformation Succeeded' END AS transformation_status;
